class Solution:
    def isPalindrome(self, s: str) -> bool:
        sl = s.lower().replace("-", "").replace(":","").replace(",", "").replace(" ", "").replace(".", "").replace("/", "").replace("\\", "").replace("_", "").replace("@", "").replace("#", "").replace("%", "").replace("$", "").replace("!", "").replace("^", "").replace("&", "").replace("*", "").replace("(", "").replace(")", "").replace("+", "").replace("-", "").replace("{", "").replace("}", "").replace("'", "").replace('"', "").replace("~", "").replace("`", "").replace("[", "").replace("]", "").replace("|", "").replace("?", "").replace(";", "")
        return sl == sl[::-1]     